class Solution:
    def twoSum(self, nums: list[int], target: int) -> list[int]:
        seen: dict[int, int] = {}          # 字典:记录「见过的数 -> 它的下标」,查询 O(1)
        for i, x in enumerate(nums):       # enumerate 同时拿到下标 i 和值 x
            # := 海象运算符:先算 seen.get(target - x) 存进 j,再判断
            # seen.get(k) 在 k 不存在时返回 None,不会报错
            if (j := seen.get(target - x)) is not None:
                return [j, i]              # 命中:之前那个数的下标 j + 当前下标 i
            seen[x] = i                    # 没命中:把当前数和下标记进字典
        return []                          # 题目保证有解,通常走不到这里

