class Solution:
    def longestPalindrome(self, s: str) -> str:
        if not s:
            return ""

        def expand(l, r):            # 从中心向两边扩,返回最大回文的左右下标
            while l >= 0 and r < len(s) and s[l] == s[r]:
                l -= 1; r += 1
            return l + 1, r - 1      # 退出时各多走一步,回退

        bl, br = 0, 0
        for i in range(len(s)):
            # 两种中心:i(奇数长)和 i,i+1(偶数长)
            for l0, r0 in (expand(i, i), expand(i, i + 1)):
                if r0 - l0 > br - bl:    # 更长就更新
                    bl, br = l0, r0
        return s[bl:br + 1]

