class Solution:
    def longestValidParentheses(self, s: str) -> int:
        st = [-1]                    # 栈底垫 -1,作「上一个未匹配位置」的基准
        ans = 0
        for i, c in enumerate(s):
            if c == "(":
                st.append(i)         # 左括号下标入栈
            else:
                st.pop()             # 右括号:弹出一个
                if not st:           # 弹空了 -> 当前 ')' 没人配,作为新基准
                    st.append(i)
                else:                # 栈顶是最近未匹配位置,i 到它的距离即有效长度
                    ans = max(ans, i - st[-1])
        return ans

