class Solution:
    def search(self, nums: list[int], target: int) -> int:
        l, r = 0, len(nums) - 1
        while l <= r:
            m = (l + r) // 2
            if nums[m] == target:
                return m
            if nums[l] <= nums[m]:               # 左半 [l..m] 是升序的
                if nums[l] <= target < nums[m]:  # target 落在左半 -> 收右边界
                    r = m - 1
                else:
                    l = m + 1
            else:                                # 右半 [m..r] 是升序的
                if nums[m] < target <= nums[r]:  # target 落在右半 -> 收左边界
                    l = m + 1
                else:
                    r = m - 1
        return -1

