class Solution:
    def firstMissingPositive(self, nums: list[int]) -> int:
        n = len(nums)
        for i in range(n):
            # 把值在 [1,n] 内的数 x 放到它该在的位置(下标 x-1)
            # 第二个条件 nums[nums[i]-1] != nums[i]:目标位还没放对,避免重复值死循环
            while 1 <= nums[i] <= n and nums[nums[i] - 1] != nums[i]:
                j = nums[i] - 1                       # x 应放到下标 j = x-1
                nums[i], nums[j] = nums[j], nums[i]   # 交换,把 x 换到正确位置
        for i in range(n):
            if nums[i] != i + 1:                      # 第一个「下标 i 上不是 i+1」的位置
                return i + 1                          # 缺失的就是 i+1
        return n + 1                                  # 1..n 全在 -> 答案是 n+1

