class Solution:
    def solveNQueens(self, n: int) -> list[list[str]]:
        cols, diag1, diag2 = set(), set(), set()   # 已占用的列、主对角线、副对角线
        ans, board = [], [-1] * n      # board[r] = 第 r 行皇后所在列

        def render():                  # 把 board 翻译成 ["..Q.", ...] 棋盘字符串
            return [
                "".join("Q" if c == board[r] else "." for c in range(n))
                for r in range(n)
            ]

        def bt(r):                     # 逐行放皇后
            if r == n:
                ans.append(render())
                return
            for c in range(n):
                # 同列、主对角线(r-c 相同)、副对角线(r+c 相同)冲突则跳过
                if c in cols or (r - c) in diag1 or (r + c) in diag2:
                    continue
                board[r] = c
                cols.add(c); diag1.add(r - c); diag2.add(r + c)
                bt(r + 1)
                cols.remove(c); diag1.remove(r - c); diag2.remove(r + c)   # 回溯

        bt(0)
        return ans

