class Solution:
    def spiralOrder(self, m: list[list[int]]) -> list[int]:
        if not m:
            return []
        top, bottom, left, right = 0, len(m) - 1, 0, len(m[0]) - 1   # 四条边界
        out: list[int] = []
        while top <= bottom and left <= right:
            for c in range(left, right + 1):    # ① 上边:从左到右
                out.append(m[top][c])
            top += 1                            # 上边用完,上界下移
            for r in range(top, bottom + 1):    # ② 右边:从上到下
                out.append(m[r][right])
            right -= 1                          # 右边用完,右界左移
            if top <= bottom:                   # ③ 下边:从右到左(需还有行)
                for c in range(right, left - 1, -1):
                    out.append(m[bottom][c])
                bottom -= 1
            if left <= right:                   # ④ 左边:从下到上(需还有列)
                for r in range(bottom, top - 1, -1):
                    out.append(m[r][left])
                left += 1
        return out

