class Solution:
    def minDistance(self, a: str, b: str) -> int:
        m, n = len(a), len(b)
        f = [[0] * (n + 1) for _ in range(m + 1)]   # f[i][j]:a 前 i 变成 b 前 j 的最少操作
        for i in range(m + 1):
            f[i][0] = i              # b 为空:删 i 次
        for j in range(n + 1):
            f[0][j] = j              # a 为空:插 j 次
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if a[i - 1] == b[j - 1]:   # 末字符相同 -> 不操作,继承对角线
                    f[i][j] = f[i - 1][j - 1]
                else:                # 替换/删除/插入 三者取最小 + 1
                    f[i][j] = 1 + min(f[i - 1][j - 1], f[i - 1][j], f[i][j - 1])
        return f[m][n]

