class Solution:
    def setZeroes(self, m: list[list[int]]) -> None:
        rows, cols = len(m), len(m[0])
        # 先单独记录首行/首列自身是否含 0(它们将被用作标记区,会被覆盖)
        first_row_zero = any(m[0][c] == 0 for c in range(cols))
        first_col_zero = any(m[r][0] == 0 for r in range(rows))
        # 用首行首列当标记:某格为 0,就把它的行首、列首标 0
        for r in range(1, rows):
            for c in range(1, cols):
                if m[r][c] == 0:
                    m[r][0] = m[0][c] = 0
        # 根据标记,把内部对应格置零
        for r in range(1, rows):
            for c in range(1, cols):
                if m[r][0] == 0 or m[0][c] == 0:
                    m[r][c] = 0
        # 最后再处理首行 / 首列本身
        if first_row_zero:
            for c in range(cols):
                m[0][c] = 0
        if first_col_zero:
            for r in range(rows):
                m[r][0] = 0

