class Solution:
    def searchMatrix(self, m: list[list[int]], target: int) -> bool:
        if not m or not m[0]:
            return False
        rows, cols = len(m), len(m[0])
        l, r = 0, rows * cols - 1    # 把整个矩阵看成长度 rows*cols 的有序数组
        while l <= r:
            mid = (l + r) // 2
            v = m[mid // cols][mid % cols]   # 一维下标 mid -> 行 mid//cols,列 mid%cols
            if v == target:
                return True
            if v < target:
                l = mid + 1
            else:
                r = mid - 1
        return False

