class Solution:
    def sortList(self, head):
        if not head or not head.next:    # 0 或 1 个结点,已有序
            return head
        # 快慢指针找中点,prev 停在中点前一个,用于断开
        prev, slow, fast = None, head, head
        while fast and fast.next:
            prev = slow
            slow = slow.next
            fast = fast.next.next
        prev.next = None                 # 从中间断成两半:head.. 和 slow..
        return _merge(self.sortList(head), self.sortList(slow))  # 递归排两半再合并

