            if c not in cur.ch:
                return None
            cur = cur.ch[c]
        return cur

    def search(self, word: str) -> bool:
        n = self._walk(word)
        return n is not None and n.end   # 既要走得通,终点还得是某单词结尾

    def startsWith(self, prefix: str) -> bool:
        return self._walk(prefix) is not None   # 走得通即存在该前缀

