        heapq.heappush(self.lo, -num)              # 先进 lo
        heapq.heappush(self.hi, -heapq.heappop(self.lo))  # 把 lo 的最大值挪到 hi,保证 lo 全 <= hi
        if len(self.hi) > len(self.lo):            # 维持 lo 个数 >= hi
            heapq.heappush(self.lo, -heapq.heappop(self.hi))

    def findMedian(self) -> float:
        if len(self.lo) > len(self.hi):            # 总数为奇 -> 中位数在 lo 顶
            return float(-self.lo[0])
        return (-self.lo[0] + self.hi[0]) / 2      # 偶 -> 两个堆顶取平均

