from collections import deque

class Solution:
    def orangesRotting(self, g: list[list[int]]) -> int:
        m, n = len(g), len(g[0])
        q = deque()
        fresh = 0
        for i in range(m):           # 先收集所有初始腐烂橘子(多源)并数新鲜橘子
            for j in range(n):
                if g[i][j] == 2:
                    q.append((i, j))
                elif g[i][j] == 1:
                    fresh += 1
        if fresh == 0:               # 没有新鲜橘子 -> 0 分钟
            return 0
        minutes = 0
        while q and fresh:           # 一层 = 一分钟,当前所有腐烂橘子同时向外传染
            for _ in range(len(q)):
                x, y = q.popleft()
                for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and g[nx][ny] == 1:
                        g[nx][ny] = 2        # 传染:新鲜 -> 腐烂
                        fresh -= 1
                        q.append((nx, ny))
            minutes += 1
        return minutes if fresh == 0 else -1   # 仍有新鲜橘子(被隔开)-> -1

