class Solution:
    def longestCommonSubsequence(self, a: str, b: str) -> int:
        m, n = len(a), len(b)
        f = [[0] * (n + 1) for _ in range(m + 1)]   # f[i][j]:a 前 i、b 前 j 的 LCS 长度
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if a[i - 1] == b[j - 1]:   # 末字符相同 -> 对角线 + 1
                    f[i][j] = f[i - 1][j - 1] + 1
                else:                # 不同 -> 去掉 a 末 或 b 末,取较大
                    f[i][j] = max(f[i - 1][j], f[i][j - 1])
        return f[m][n]
